static size_t CalculateTreeSize(const unsigned *ll_lengths,
                                const unsigned *d_lengths)
{
    size_t result = 0;
    int i;

    for (i = 0; i < 8; i++)
    {
        size_t size = EncodeTree(ll_lengths, d_lengths,
                                 i & 1, i & 2, i & 4,
                                 0, 0, 0);
        if (result == 0 || size < result)
            result = size;
    }

    return result;
}

